import React, { useState } from 'react';
import axios from "axios";

const RegisterPage = () => {
    const [email, setEmail] = useState('');
    const [name, setName] = useState('');
    const [phone, setPhone] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');

    const handleSubmit = (e) => {
        e.preventDefault();

        if (!email || !password || !confirmPassword || !phone || !name) {
            setError('Please fill out all fields');
            return;
        }

        if (password !== confirmPassword) {
            setError('Passwords do not match');
            return;
        }

        // You can add actual registration logic here (e.g., calling an API)
        console.log('Registering with', { email, password });

        let response = null;
        const register = async () => {
            response = await axios.post("http://localhost:3003/user/register", {
                name: name,
                password: password,
                email: email,
                phone: phone,
            })
        }

        try {
            register();

            if (200 !== response.status) {
                console.log("200 !== response.status). response: " + response);
                throw new Error('Registration failed, please try again.');
            }
        } catch (error) {
            console.log("error is: " + error);
            console.log("response: " + response);
        }


    };

    return (
        <div style={styles.container}>
            <h2>Create an Account</h2>
            {error && <div style={styles.error}>{error}</div>}
            <form onSubmit={handleSubmit}>
                <div style={styles.inputContainer}>
                    <label>Name</label>
                    <input
                        type="name"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your name"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Email</label>
                    <input
                        type="email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your email"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Password</label>
                    <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your password"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Confirm Password</label>
                    <input
                        type="password"
                        value={confirmPassword}
                        onChange={(e) => setConfirmPassword(e.target.value)}
                        style={styles.input}
                        placeholder="Confirm your password"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Phone</label>
                    <input
                        type="phone"
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your phone number"
                    />
                </div>
                <button type="submit" style={styles.button}>Register</button>
            </form>
            <div style={styles.redirect}>
                <p>Already have an account? <a href="/login">Login here</a></p>
            </div>
        </div>
    );
};

const styles = {
    container: {
        maxWidth: '400px',
        margin: 'auto',
        padding: '20px',
        backgroundColor: '#f9f9f9',
        borderRadius: '8px',
        boxShadow: '0 4px 8px rgba(0, 0, 0, 0.1)',
    },
    inputContainer: {
        marginBottom: '15px',
    },
    input: {
        width: '100%',
        padding: '10px',
        marginTop: '5px',
        borderRadius: '5px',
        border: '1px solid #ccc',
    },
    button: {
        width: '100%',
        padding: '12px',
        backgroundColor: '#007bff',
        color: 'white',
        border: 'none',
        borderRadius: '5px',
        fontSize: '16px',
        cursor: 'pointer',
    },
    error: {
        color: 'red',
        marginBottom: '10px',
    },
    redirect: {
        marginTop: '10px',
        textAlign: 'center',
    },
};

export default RegisterPage;
